package structs

type SandboxVolume struct {
	// ID is a UUID-like string generated by the server.
	ID string

	// Namespace is the Nomad namespace for the host volume, which constrains
	// which jobs can mount it.
	Namespace string

	// Name is the name that group.volume will use to identify the volume
	// source. Not expected to be unique.
	Name string

	// AllocID is the allocation that claims this sandbox. May be empty if no
	// allocation currently claims the sandbox.
	AllocID string

	// NodeID is the node where the volume is placed.
	NodeID string

	// Size of the sandbox in bytes
	CapacityBytes int64

	CreateIndex uint64
	CreateTime  int64 // Unix timestamp in nanoseconds since epoch

	ModifyIndex uint64
	ModifyTime  int64 // Unix timestamp in nanoseconds since epoch
}

func (v *SandboxVolume) Copy() *SandboxVolume {
	if v == nil {
		return nil
	}

	nv := *v
	return &nv
}
